#!/bin/bash
# FIX_PROXY_v2.sh - Patch tiktok.py avec strategie HTTP directe + restart
set -e
cd /opt/clip-scraper

echo "============================================================"
echo "  FIX PROXY v2 - strategie HTTP directe"
echo "============================================================"

# --- Patch tiktok.py v2 (avec strat HTTP directe) ---
B64=''
echo "$B64" | base64 -d > /opt/clip-scraper/scrapers/tiktok.py
echo "[OK] tiktok.py v2 (taille: $(wc -c < /opt/clip-scraper/scrapers/tiktok.py) octets)"

echo "[..] Restart container..."
docker compose restart
sleep 20

echo ""
echo "[TEST FINAL] Scrape TikTok via le scraper..."
curl -s -X POST "http://localhost:8001/v1/tiktok/khaby.lame?max_videos=3" \
  -H "X-API-Key: cd-prod-ac29858a696cf2c1a642dd1c9f607628fcd8b0878cc3c704" \
  --max-time 60 | head -c 1500
echo ""
echo ""
echo "[LOGS]"
docker logs clip-scraper --tail 10 2>&1
echo ""
echo "============================================================"
echo "Si tu vois videos:[...] avec des objets dedans = SUCCES"
echo "============================================================"
